// ── UTILITIES ─────────────────────────────────────────────────────────────────

const PARTICLES = new Set(["van","de","den","der","von","di","da","le","la","el","al","du","dos","das"]);

function normalise(s) {
  return s.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").trim();
}

function getSurname(name) {
  const parts = normalise(name).split(" ");
  if (parts.length === 1) return parts[0];
  for (let i = 0; i < parts.length - 1; i++) {
    if (PARTICLES.has(parts[i])) return parts.slice(i).join(" ");
  }
  return parts[parts.length - 1];
}

// Returns array of player indices that match the input
function getMatchingPlayers(players, input) {
  const n = normalise(input.trim());
  if (n.length < 2) return [];
  return players.reduce((acc, p, i) => {
    const surname = getSurname(p.name);
    const full = normalise(p.name);
    if (n === surname || n === full) acc.push(i);
    return acc;
  }, []);
}

// ── POSITION LAYOUT ──────────────────────────────────────────────────────────

const ROW_MAP = {
  GK:6, SW:5, RB:5, CB:5, LB:5,
  LWB:4, RWB:4,
  DM:3, CDM:3,
  RM:2, CM:2, LM:2, WM:2,
  AM:1, CAM:1,
  RW:0, LW:0, FW:0, ST:0, CF:0,
};

// Lateral order within a row: negative = left, 0 = centre, positive = right
const LATERAL = {
  GK:0, SW:0,
  LB:-2, CB:0, RB:2,
  LWB:-3, RWB:3,
  DM:0, CDM:0,
  LM:-2, CM:0, RM:2, WM:0,
  CAM:0, AM:0,
  LW:-2, CF:0, ST:0, FW:0, RW:2,
};

function computeLayout(players) {
  const rows = {};
  players.forEach((p, i) => {
    const r = ROW_MAP[p.pos] ?? 2;
    (rows[r] = rows[r] || []).push({ ...p, idx: i });
  });
  const result = [];
  Object.entries(rows).forEach(([rStr, ps]) => {
    const r = +rStr;
    // Sort left → right by lateral priority so LB/LM/LW land on the left,
    // CB/CM/ST land in the centre, and RB/RM/RW land on the right
    const sorted = [...ps].sort((a, b) => (LATERAL[a.pos] ?? 0) - (LATERAL[b.pos] ?? 0));
    const count = sorted.length;
    sorted.forEach((p, i) => {
      result.push({
        ...p,
        coords: {
          left: count === 1 ? 50 : 12 + (76 * i) / (count - 1),
          top: 6 + (r / 6) * 86,
        }
      });
    });
  });
  return result;
}

// ── DAILY MATCH ───────────────────────────────────────────────────────────────

function getMatch() {
  const epoch = new Date("2025-01-01").getTime();
  const today = new Date(); today.setHours(0,0,0,0);
  const idx = Math.floor((today.getTime() - epoch) / 86400000);
  return MATCHES[((idx % MATCHES.length) + MATCHES.length) % MATCHES.length];
}

const TIMER_SECS = 600;

// ── STORAGE ───────────────────────────────────────────────────────────────────

async function loadLB() {
  try { const r = await window.storage.get("gxi-lb-v4", true); return r ? JSON.parse(r.value) : []; }
  catch { return []; }
}
async function saveLB(lb) {
  try { await window.storage.set("gxi-lb-v4", JSON.stringify(lb), true); } catch {}
}
async function loadProg() {
  try { const r = await window.storage.get(`gxi-prog-${new Date().toISOString().slice(0,10)}`); return r ? JSON.parse(r.value) : null; }
  catch { return null; }
}
async function saveProg(d) {
  try { await window.storage.set(`gxi-prog-${new Date().toISOString().slice(0,10)}`, JSON.stringify(d)); } catch {}
}

// ── PITCH COMPONENT ───────────────────────────────────────────────────────────

function Pitch({ layout, guessedIdx, shakeIdx }) {
  return (
    <div style={{
      position:"relative", width:"100%", paddingBottom:"138%",
      background:"repeating-linear-gradient(180deg,#2a6329 0px,#2a6329 26px,#306e2f 26px,#306e2f 52px)",
      borderRadius:8, border:"2px solid #1a3d19", overflow:"hidden",
      boxShadow:"inset 0 0 40px rgba(0,0,0,0.4)"
    }}>
      {/* Logo watermark */}
      <div style={{
        position:"absolute", inset:0,
        display:"flex", alignItems:"center", justifyContent:"center",
        zIndex:1, pointerEvents:"none"
      }}>
        <img src={LOGO} alt="" style={{
          width:"62%", opacity:0.07,
          filter:"grayscale(1)",
          userSelect:"none"
        }}/>
      </div>

      {/* Pitch markings */}
      <svg style={{position:"absolute",inset:0,width:"100%",height:"100%",zIndex:2}} viewBox="0 0 100 138" preserveAspectRatio="none">
        <rect x="5" y="4" width="90" height="130" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="0.5"/>
        <line x1="5" y1="69" x2="95" y2="69" stroke="rgba(255,255,255,0.3)" strokeWidth="0.5"/>
        <circle cx="50" cy="69" r="11" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="0.5"/>
        <circle cx="50" cy="69" r="0.7" fill="rgba(255,255,255,0.5)"/>
        <rect x="23" y="4" width="54" height="20" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="0.4"/>
        <rect x="23" y="114" width="54" height="20" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="0.4"/>
        <rect x="37" y="4" width="26" height="8" fill="none" stroke="rgba(255,255,255,0.15)" strokeWidth="0.3"/>
        <rect x="37" y="126" width="26" height="8" fill="none" stroke="rgba(255,255,255,0.15)" strokeWidth="0.3"/>
      </svg>

      {/* Player slots */}
      {layout.map((p) => {
        const done = guessedIdx.has(p.idx);
        const shaking = shakeIdx === p.idx;
        const nameParts = p.name.split(" ");
        const surname = nameParts.slice(-1)[0].toUpperCase();
        const firstname = nameParts.slice(0,-1).join(" ");

        return (
          <div key={p.idx} style={{
            position:"absolute",
            left:`${p.coords.left}%`, top:`${p.coords.top}%`,
            transform:"translate(-50%,-50%)",
            width:58, textAlign:"center",
            animation: shaking ? "shake 0.4s ease" : "none",
            zIndex:10, userSelect:"none",
          }}>
            {/* Circle badge */}
            <div style={{
              width:38, height:38, margin:"0 auto 3px",
              borderRadius:"50%",
              background: done
                ? "linear-gradient(135deg,#DB0007,#8b0004)"
                : "rgba(0,0,0,0.5)",
              border: done
                ? "2px solid rgba(255,100,100,0.6)"
                : "2px dashed rgba(255,255,255,0.3)",
              display:"flex", alignItems:"center", justifyContent:"center",
              transition:"all 0.25s ease",
              boxShadow: done ? "0 0 14px rgba(219,0,7,0.5)" : "none",
            }}>
              {done ? (
                <span style={{color:"#fff",fontSize:11,fontWeight:700,fontFamily:"monospace"}}>
                  {p.shirt}
                </span>
              ) : (
                <span style={{color:"rgba(255,255,255,0.4)",fontSize:13}}>?</span>
              )}
            </div>
            {/* Name label */}
            <div style={{
              background: done ? "rgba(0,0,0,0.88)" : "rgba(0,0,0,0.5)",
              borderRadius:3, padding:"2px 4px",
              minWidth:54, maxWidth:70, margin:"0 auto",
            }}>
              <div style={{
                color: done ? "#fff" : "rgba(255,255,255,0.35)",
                fontSize:9, fontWeight:700,
                fontFamily:"'Barlow Condensed',sans-serif",
                letterSpacing:"0.04em", lineHeight:1.2,
                whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis",
              }}>
                {done ? surname : p.pos}
              </div>
              {done && firstname && (
                <div style={{
                  color:"#DB0007", fontSize:"7.5px",
                  fontFamily:"monospace", marginTop:1,
                  whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis",
                }}>
                  {firstname}
                </div>
              )}
            </div>
          </div>
        );
      })}

      <style>{`
        @keyframes shake {
          0%,100%{transform:translate(-50%,-50%)}
          20%{transform:translate(calc(-50% - 6px),-50%)}
          60%{transform:translate(calc(-50% + 6px),-50%)}
          80%{transform:translate(calc(-50% - 3px),-50%)}
        }
      `}</style>
    </div>
  );
}

// ── MAIN APP ──────────────────────────────────────────────────────────────────

export default function App() {
  const match = getMatch();
  const layout = computeLayout(match.players);
  const today = new Date().toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"});
  const todayKey = new Date().toISOString().slice(0,10);

  // Phase: "lobby" | "playing" | "done" | "score"
  const [phase, setPhase]         = useState("lobby");
  const [guessedIdx, setGuessedIdx] = useState(new Set());
  const [input, setInput]         = useState("");
  const [shakeIdx, setShakeIdx]   = useState(null);
  const [seconds, setSeconds]     = useState(TIMER_SECS);
  const [nameEntry, setNameEntry] = useState("");
  const [leaderboard, setLeaderboard] = useState([]);
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading]     = useState(true);
  const inputRef = useRef(null);

  // Load progress + leaderboard
  useEffect(() => {
    (async () => {
      const [lb, prog] = await Promise.all([loadLB(), loadProg()]);
      setLeaderboard(lb);
      if (prog && prog.todayId === match.id) {
        const restored = new Set(prog.guessedIdx || []);
        setGuessedIdx(restored);
        setSeconds(prog.seconds ?? TIMER_SECS);
        setPhase(prog.phase || "lobby");
      }
      setLoading(false);
    })();
  }, []);

  // Auto-save
  useEffect(() => {
    if (!loading) saveProg({ todayId: match.id, guessedIdx: [...guessedIdx], seconds, phase });
  }, [guessedIdx, seconds, phase, loading]);

  // Timer
  useEffect(() => {
    if (phase !== "playing") return;
    if (seconds <= 0) { setPhase("done"); return; }
    const t = setInterval(() => setSeconds(s => {
      if (s <= 1) { setPhase("done"); return 0; }
      return s - 1;
    }), 1000);
    return () => clearInterval(t);
  }, [phase, seconds]);

  // Focus input when playing
  useEffect(() => {
    if (phase === "playing") inputRef.current?.focus();
  }, [phase]);

  // Called on every keystroke — auto-fills the moment surname matches
  function handleChange(val) {
    setInput(val);
    const hits = getMatchingPlayers(match.players, val);
    const newHits = hits.filter(i => !guessedIdx.has(i));
    if (newHits.length > 0) {
      const next = new Set([...guessedIdx, ...newHits]);
      setGuessedIdx(next);
      setInput("");
      if (next.size === match.players.length) setPhase("done");
    }
  }

  // Called on Enter/button — for wrong guesses shows shake feedback
  function handleGuess() {
    if (phase !== "playing") return;
    const hits = getMatchingPlayers(match.players, input);
    const newHits = hits.filter(i => !guessedIdx.has(i));
    if (newHits.length > 0) {
      const next = new Set([...guessedIdx, ...newHits]);
      setGuessedIdx(next);
      setInput("");
      if (next.size === match.players.length) setPhase("done");
    } else {
      setShakeIdx(-1);
      setTimeout(() => setShakeIdx(null), 400);
      setInput("");
    }
  }

  async function handleSubmitScore() {
    if (!nameEntry.trim()) return;
    const elapsed = TIMER_SECS - seconds;
    const entry = {
      name: nameEntry.trim().slice(0, 20),
      solved: guessedIdx.size,
      total: match.players.length,
      time: elapsed,
      date: todayKey,
      matchLabel: `${match.opponent} ${match.season}`,
    };
    const updated = [...leaderboard, entry]
      .sort((a, b) => b.solved - a.solved || a.time - b.time)
      .slice(0, 50);
    setLeaderboard(updated);
    await saveLB(updated);
    setSubmitted(true);
  }

  async function handleReset() {
    try { await window.storage.delete(`gxi-prog-${new Date().toISOString().slice(0,10)}`); } catch {}
    setGuessedIdx(new Set());
    setInput("");
    setShakeIdx(null);
    setSeconds(TIMER_SECS);
    setNameEntry("");
    setSubmitted(false);
    setPhase("lobby");
  }

  const mm = Math.floor(seconds / 60).toString().padStart(2, "0");
  const ss = (seconds % 60).toString().padStart(2, "0");
  const timerColour = seconds > 120 ? "#4caf50" : seconds > 30 ? "#ff9800" : "#f44336";
  const todayLB = leaderboard.filter(e => e.date === todayKey);

  if (loading) return (
    <div style={{minHeight:"100vh",background:"#0d0d1a",display:"flex",alignItems:"center",
      justifyContent:"center",color:"#fff",fontFamily:"Barlow Condensed,sans-serif",fontSize:24}}>
      Loading…
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:"#0d0d1a",color:"#fff",
      fontFamily:"'Barlow', sans-serif",paddingBottom:40}}>

      {/* Header */}
      <div style={{background:"#B30000",borderBottom:"3px solid #7a0000"}}>
        <div style={{maxWidth:480,margin:"0 auto",padding:"10px 14px",
          display:"flex",alignItems:"center",justifyContent:"space-between",gap:10}}>

          {/* TL Gunners logo */}
          <div style={{display:"flex",alignItems:"center",gap:10,flexShrink:0}}>
            {/* TG Logo */}
            <img src={LOGO} alt="TL Gunners" style={{
              width:48, height:48, objectFit:"contain",
              filter:"drop-shadow(0 2px 6px rgba(0,0,0,0.5))"
            }}/>
            <div>
              <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,
                fontSize:11,letterSpacing:3,textTransform:"uppercase",opacity:.75,lineHeight:1}}>
                TL GUNNERS
              </div>
              <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,
                fontSize:22,letterSpacing:4,textTransform:"uppercase",lineHeight:1}}>
                GUNNERS XI
              </div>
            </div>
          </div>

          {/* Date + Reset */}
          <div style={{textAlign:"right",flexShrink:0}}>
            <div style={{fontSize:11,opacity:.65,letterSpacing:.5}}>{today}</div>
            <button onClick={handleReset}
              style={{marginTop:4,background:"rgba(0,0,0,0.25)",border:"1px solid rgba(255,255,255,0.2)",
                color:"rgba(255,255,255,0.7)",fontSize:10,padding:"3px 8px",
                borderRadius:4,cursor:"pointer",fontFamily:"'Barlow Condensed',sans-serif",
                letterSpacing:1,textTransform:"uppercase"}}>
              ↺ Reset
            </button>
          </div>
        </div>
      </div>

      <div style={{maxWidth:480,margin:"0 auto",padding:"14px 12px 0"}}>

        {/* Match info card */}
        <div style={{background:"rgba(255,255,255,0.05)",borderRadius:10,padding:"12px 16px",
          marginBottom:12,border:"1px solid rgba(255,255,255,0.08)"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",
            flexWrap:"wrap",gap:4}}>
            <div>
              <span style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,
                fontSize:20,color:"#DB0007"}}>vs {match.opponent}</span>
              <span style={{fontSize:14,opacity:.55,marginLeft:8}}>{match.score}</span>
            </div>
            <div style={{fontSize:11,opacity:.45}}>{match.competition} · {match.season}</div>
          </div>
          <div style={{fontSize:12,opacity:.5,marginTop:4,fontStyle:"italic"}}>{match.context}</div>
          <div style={{display:"flex",gap:16,marginTop:8,fontSize:12}}>
            <span style={{opacity:.7}}>📐 {match.formation}</span>
            {phase !== "lobby" && (
              <span style={{color: guessedIdx.size === match.players.length ? "#66bb6a":"rgba(255,255,255,.7)"}}>
                ✅ {guessedIdx.size}/{match.players.length}
              </span>
            )}
          </div>
        </div>

        {/* ── LOBBY ── */}
        {phase === "lobby" && (
          <div style={{textAlign:"center",padding:"20px 0"}}>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,
              fontSize:16,letterSpacing:2,opacity:.5,textTransform:"uppercase",marginBottom:16}}>
              Name all 11 starters — you have 10 minutes
            </div>
            <button onClick={() => setPhase("playing")}
              style={{background:"linear-gradient(135deg,#DB0007,#8b0004)",border:"none",
                color:"#fff",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,
                fontSize:22,letterSpacing:4,textTransform:"uppercase",padding:"16px 48px",
                borderRadius:8,cursor:"pointer",boxShadow:"0 4px 20px rgba(219,0,7,0.4)",
                transition:"all .2s"}}>
              KICK OFF
            </button>
            <div style={{marginTop:12,fontSize:12,opacity:.4}}>
              Type a player's surname — auto-fills when correct
            </div>
          </div>
        )}

        {/* ── PITCH (shown while playing or done) ── */}
        {phase !== "lobby" && (
          <>
            {/* Timer row */}
            {phase === "playing" && (
              <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:8}}>
                <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:32,
                  fontWeight:900,color:timerColour,letterSpacing:2,minWidth:80}}>
                  {mm}:{ss}
                </div>
                <div style={{flex:1,height:4,background:"rgba(255,255,255,.08)",borderRadius:2}}>
                  <div style={{height:"100%",width:`${(seconds/TIMER_SECS)*100}%`,
                    background:timerColour,borderRadius:2,transition:"width .5s linear"}}/>
                </div>
                <button onClick={() => setPhase("done")}
                  style={{background:"none",border:"1px solid rgba(255,255,255,.15)",
                    color:"rgba(255,255,255,.45)",fontSize:11,padding:"4px 8px",
                    borderRadius:4,cursor:"pointer",fontFamily:"'Barlow Condensed',sans-serif",
                    letterSpacing:1,textTransform:"uppercase"}}>
                  Give up
                </button>
              </div>
            )}

            <Pitch layout={layout} guessedIdx={guessedIdx} shakeIdx={shakeIdx}/>

            {/* Input */}
            {phase === "playing" && (
              <div style={{marginTop:10}}>
                <div style={{display:"flex",gap:8}}>
                  <input
                    ref={inputRef}
                    value={input}
                    onChange={e => handleChange(e.target.value)}
                    onKeyDown={e => { if (e.key==="Enter") { e.preventDefault(); handleGuess(); }}}
                    placeholder="Type a player's surname…"
                    autoComplete="off"
                    style={{flex:1,padding:"11px 14px",borderRadius:8,
                      border:`2px solid ${shakeIdx!=null?"#f44336":"rgba(255,255,255,0.15)"}`,
                      background:"rgba(255,255,255,0.07)",color:"#fff",fontSize:16,
                      fontFamily:"'Barlow Condensed',sans-serif",letterSpacing:.5,
                      transition:"border .2s"}}
                  />
                  <button onClick={handleGuess}
                    style={{padding:"11px 18px",borderRadius:8,
                      background:"linear-gradient(135deg,#DB0007,#8b0004)",
                      border:"none",color:"#fff",fontSize:16,
                      fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,
                      letterSpacing:1,cursor:"pointer"}}>
                    ↵
                  </button>
                </div>
                <div style={{marginTop:5,fontSize:11,opacity:.4,textAlign:"center"}}>
                  Auto-fills on correct answer · Surname only · {match.players.length - guessedIdx.size} remaining
                </div>
              </div>
            )}

            {/* ── DONE SCREEN ── */}
            {phase === "done" && !submitted && (
              <div style={{marginTop:12,background:"rgba(255,255,255,.06)",borderRadius:10,
                padding:"16px",border:"1px solid rgba(255,255,255,.1)"}}>
                <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:22,
                  color:guessedIdx.size===match.players.length?"#66bb6a":"#ef5350",marginBottom:6}}>
                  {guessedIdx.size===match.players.length ? "🏆 Perfect XI! Full house!" : "⏱ Full time!"}
                </div>
                <div style={{fontSize:14,marginBottom:12,opacity:.75}}>
                  {guessedIdx.size}/{match.players.length} players identified in{" "}
                  {Math.floor((TIMER_SECS-seconds)/60)}m {(TIMER_SECS-seconds)%60}s
                </div>
                {/* Full reveal */}
                <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>
                  {match.players.map((p,i) => (
                    <span key={i} style={{padding:"3px 9px",borderRadius:4,fontSize:12,
                      fontFamily:"'Barlow Condensed',sans-serif",letterSpacing:.5,
                      background:guessedIdx.has(i)?"rgba(102,187,106,.15)":"rgba(219,0,7,.12)",
                      border:`1px solid ${guessedIdx.has(i)?"#66bb6a":"rgba(219,0,7,.4)"}`,
                      color:guessedIdx.has(i)?"#a5d6a7":"rgba(255,150,150,.9)"}}>
                      {p.name}
                    </span>
                  ))}
                </div>
                {/* Score entry */}
                <div style={{borderTop:"1px solid rgba(255,255,255,.08)",paddingTop:12}}>
                  <div style={{fontSize:12,opacity:.55,marginBottom:8}}>Add your name to the leaderboard:</div>
                  <div style={{display:"flex",gap:8}}>
                    <input value={nameEntry} onChange={e=>setNameEntry(e.target.value)}
                      onKeyDown={e=>{ if(e.key==="Enter") handleSubmitScore(); }}
                      placeholder="Your name…" maxLength={20}
                      style={{flex:1,padding:"9px 12px",borderRadius:6,
                        border:"1px solid rgba(255,255,255,.15)",
                        background:"rgba(255,255,255,.07)",color:"#fff",fontSize:14}}/>
                    <button onClick={handleSubmitScore}
                      style={{padding:"9px 16px",borderRadius:6,
                        background:"linear-gradient(135deg,#DB0007,#8b0004)",
                        border:"none",color:"#fff",fontFamily:"'Barlow Condensed',sans-serif",
                        fontWeight:700,letterSpacing:1,cursor:"pointer"}}>
                      SUBMIT
                    </button>
                  </div>
                </div>
              </div>
            )}

            {/* Post-submit view */}
            {phase === "done" && submitted && (
              <div style={{marginTop:12,background:"rgba(255,255,255,.06)",borderRadius:10,
                padding:"16px",border:"1px solid rgba(255,255,255,.1)"}}>
                <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,
                  fontSize:16,color:"#66bb6a",marginBottom:10}}>✅ Submitted!</div>
                <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>
                  {match.players.map((p,i) => (
                    <span key={i} style={{padding:"3px 9px",borderRadius:4,fontSize:12,
                      fontFamily:"'Barlow Condensed',sans-serif",
                      background:guessedIdx.has(i)?"rgba(102,187,106,.15)":"rgba(219,0,7,.12)",
                      border:`1px solid ${guessedIdx.has(i)?"#66bb6a":"rgba(219,0,7,.4)"}`,
                      color:guessedIdx.has(i)?"#a5d6a7":"rgba(255,150,150,.9)"}}>
                      {p.name}
                    </span>
                  ))}
                </div>
                <Leaderboard entries={todayLB}/>
              </div>
            )}
          </>
        )}

        {/* Always show leaderboard in lobby if there are entries */}
        {phase === "lobby" && todayLB.length > 0 && <Leaderboard entries={todayLB}/>}
      </div>
    </div>
  );
}

function Leaderboard({ entries }) {
  if (!entries.length) return null;
  const todayKey = new Date().toISOString().slice(0,10);
  const today = entries.filter(e => e.date === todayKey);
  if (!today.length) return null;
  return (
    <div style={{marginTop:12,background:"rgba(255,255,255,.04)",borderRadius:8,
      padding:"12px 14px",border:"1px solid rgba(255,255,255,.07)"}}>
      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,fontSize:13,
        letterSpacing:2,textTransform:"uppercase",opacity:.5,marginBottom:8}}>
        🏅 Today's Leaderboard
      </div>
      {today.slice(0,10).map((e,i) => (
        <div key={i} style={{display:"flex",justifyContent:"space-between",
          padding:"5px 0",borderBottom:i<today.length-1?"1px solid rgba(255,255,255,.05)":"none",
          fontSize:13}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <span style={{color:"#ffd700",minWidth:20,fontFamily:"'Barlow Condensed',sans-serif",
              fontWeight:700}}>{i===0?"🥇":i===1?"🥈":i===2?"🥉":`#${i+1}`}</span>
            <span>{e.name}</span>
          </div>
          <div style={{opacity:.6,fontFamily:"'Barlow Condensed',sans-serif"}}>
            {e.solved}/{e.total} · {Math.floor(e.time/60)}:{String(e.time%60).padStart(2,"0")}
          </div>
        </div>
      ))}
    </div>
  );
}
